// ============================================================
// pages/AdminDashboard.jsx — Admin Panel Main Page
// ============================================================
// Lists all merchant applications with:
//  - Search by name / email
//  - Filter by status
//  - Click to view full details
// ============================================================

import React, { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { adminAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/dashboard.css";

function AdminDashboard() {
  const { logout } = useAuth();
  const navigate   = useNavigate();

  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search,  setSearch]  = useState("");
  const [status,  setStatus]  = useState("");

  // Fetch applications from API whenever search or status filter changes
  useEffect(() => {
    setLoading(true);
    adminAPI.getAllApplications({ search, status })
      .then((res) => setApplications(res.data))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [search, status]);

  // Count by status for summary cards
  const counts = {
    total:       applications.length,
    pending:     applications.filter((a) => a.status === "pending").length,
    under_review:applications.filter((a) => a.status === "under_review").length,
    approved:    applications.filter((a) => a.status === "approved").length,
    rejected:    applications.filter((a) => a.status === "rejected").length,
  };

  return (
    <div className="dashboard-layout">
      <aside className="sidebar">
        <div className="sidebar-logo" style={{ color: "#DC2626" }}>Admin Panel</div>
        <ul className="sidebar-nav">
          <li><Link to="/admin/dashboard" className="active">📋 All Applications</Link></li>
        </ul>
        <div className="sidebar-footer">
          <button onClick={logout} style={{ background:"none", border:"none", color:"var(--color-text-secondary)", cursor:"pointer", fontSize:"0.875rem" }}>
            🚪 Logout
          </button>
        </div>
      </aside>

      <main className="main-content">
        <div className="topbar">
          <div>
            <h1 className="page-title">Applications</h1>
            <p className="page-subtitle">Review and manage merchant onboarding applications</p>
          </div>
        </div>

        {/* Summary Stats */}
        <div className="stats-grid" style={{ marginBottom: "var(--space-xl)" }}>
          {[
            { label: "Total",        value: counts.total,        color: "#6B7280" },
            { label: "Pending",      value: counts.pending,      color: "#D97706" },
            { label: "Under Review", value: counts.under_review, color: "#2563EB" },
            { label: "Approved",     value: counts.approved,     color: "#16A34A" },
            { label: "Rejected",     value: counts.rejected,     color: "#DC2626" },
          ].map((s) => (
            <div className="stat-card" key={s.label}>
              <div className="stat-label">{s.label}</div>
              <div className="stat-value" style={{ color: s.color }}>{s.value}</div>
            </div>
          ))}
        </div>

        {/* Applications Table */}
        <div className="table-card">
          <div className="table-header">
            <h3>All Applications</h3>
            <div className="filter-bar">
              {/* Search box */}
              <input
                className="search-input"
                type="text"
                placeholder="Search by name or email..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
              />
              {/* Status filter */}
              <select
                className="filter-select"
                value={status}
                onChange={(e) => setStatus(e.target.value)}
              >
                <option value="">All Statuses</option>
                <option value="pending">Pending</option>
                <option value="under_review">Under Review</option>
                <option value="approved">Approved</option>
                <option value="rejected">Rejected</option>
              </select>
            </div>
          </div>

          {loading ? (
            <div className="spinner" />
          ) : applications.length === 0 ? (
            <div style={{ padding: "var(--space-2xl)", textAlign: "center", color: "var(--color-text-secondary)" }}>
              No applications found.
            </div>
          ) : (
            <table className="data-table">
              <thead>
                <tr>
                  <th>#</th>
                  <th>Business Name</th>
                  <th>Contact Person</th>
                  <th>Email</th>
                  <th>Submitted</th>
                  <th>Status</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {applications.map((app, i) => (
                  <tr key={app.id}>
                    <td>{i + 1}</td>
                    <td style={{ fontWeight: 500 }}>{app.merchant.business_name}</td>
                    <td>{app.merchant.contact_person}</td>
                    <td>{app.merchant.email}</td>
                    <td>{new Date(app.submitted_at).toLocaleDateString("en-IN")}</td>
                    <td>
                      <span className={`badge badge-${app.status}`}>
                        {app.status.replace("_", " ")}
                      </span>
                    </td>
                    <td>
                      <button
                        className="btn-link"
                        onClick={() => navigate(`/admin/applications/${app.id}`)}
                      >
                        View →
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </main>
    </div>
  );
}

export default AdminDashboard;
